const StyleProcessingAnimation: React.FC<StyleProcessingAnimationProps> = ({
  isVisible,
}) => {
  // 動畫時間線
  const timeline = {
    codeDisplay: { start: 0.3, duration: 0.2 },
    cssHighlight: { start: 0.5, duration: 0.3 },
    cssomTree: { start: 0.8, duration: 0.5 },
    selectorMatching: { start: 1.3, duration: 0.3 },
    cascadePriority: { start: 1.6, duration: 0.4 },
    styleResult: { start: 2.0, duration: 0.5 },
  };

  // 動畫變體
  const fadeInVariants = {
    hidden: { opacity: 0 },
    visible: (custom: number) => ({
      opacity: 1,
      transition: { delay: custom, duration: 0.3 },
    }),
  };

  // 代碼示例
  const htmlCode = `
<header>
  <h1>標題</h1>
</header>
<main>
  <p>內容</p>
</main>`.trim();

  const cssCode = `
header {
  background: #f0f9ff;
  padding: 2rem;
}

h1 {
  color: #1e40af;
  font-size: 2rem;
}

main {
  margin: 2rem;
}

p {
  line-height: 1.6;
}`.trim();

  return (
    <Container>
      <FlexContainer>
        {/* 代碼面板 */}
        <CodePanel
          variants={fadeInVariants}
          custom={timeline.codeDisplay.start}
          initial="hidden"
          animate={isVisible ? "visible" : "hidden"}
        >
          <DownloadAndParseIndicator
            variants={fadeInVariants}
            custom={timeline.cssomTree.start}
            initial="hidden"
            animate={isVisible ? "visible" : "hidden"}
          >
            <IndicatorStatus>
              <StatusDot />
              <StatusText>1. 下載並解析CSS文件
              </StatusText>
            </IndicatorStatus>
          </DownloadAndParseIndicator>

          {/* CSS代碼與高亮 */}
          <CodeBlock2>
            <CodeLabel>CSS</CodeLabel>
            <CodeContent>
              {cssCode}
              {/* 高亮顯示CSS選擇器部分 */}
              <CodeHighlight
                initial={{ opacity: 0, top: "0%", height: "18%" }}
                animate={isVisible ? { opacity: 1 } : { opacity: 0 }}
                transition={{
                  delay: timeline.cssHighlight.start,
                  duration: 0.1,
                }}
              />
              <CodeHighlight
                initial={{ opacity: 0, top: "25%", height: "18.6%" }}
                animate={isVisible ? { opacity: 1 } : { opacity: 0 }}
                transition={{
                  delay: timeline.cssHighlight.start + 0.3,
                  duration: 0.1,
                }}
              />
              <CodeHighlight
                initial={{ opacity: 0, top: "51%", height: "16%" }}
                animate={isVisible ? { opacity: 1 } : { opacity: 0 }}
                transition={{
                  delay: timeline.cssHighlight.start + 0.6,
                  duration: 0.1,
                }}
              />
              <CodeHighlight
                initial={{ opacity: 0, top: "72%", height: "16%" }}
                animate={isVisible ? { opacity: 1 } : { opacity: 0 }}
                transition={{
                  delay: timeline.cssHighlight.start + 0.9,
                  duration: 0.1,
                }}
              />
            </CodeContent>
          </CodeBlock2>
        </CodePanel>

        {/* 可視化面板 */}
        <VisualizationPanel>
          {/* CSSOM構建狀態指示器 */}
          <StatusIndicator
            variants={fadeInVariants}
            custom={timeline.cssomTree.start}
            initial="hidden"
            animate={isVisible ? "visible" : "hidden"}
          >
            <IndicatorStatus>
              <StatusDot />
              <StatusText>2. 將CSS規則轉換為樣式結構</StatusText>
            </IndicatorStatus>
          </StatusIndicator>

          {/* 樣式應用完成狀態指示器 */}
          <StatusIndicator
            variants={fadeInVariants}
            custom={timeline.styleResult.start}
            initial="hidden"
            animate={isVisible ? "visible" : "hidden"}
            style={{ top: "41%" }}
          >
            <IndicatorStatus>
              <StatusDot />
              <StatusText>3. 計算特定性（Specificity）</StatusText>
            </IndicatorStatus>
          </StatusIndicator>

          {/* Stylesheet根節點 */}
          <RootNodeCard
            variants={fadeInVariants}
            custom={timeline.cssomTree.start}
            initial="hidden"
            animate={isVisible ? "visible" : "hidden"}
            style={{ marginTop: "3.5%" }}
          >
            <NodeTitle>Stylesheet</NodeTitle>
            <NodeContent>root node</NodeContent>
          </RootNodeCard>

          {/* header節點 */}
          <NodeCard
            variants={fadeInVariants}
            custom={timeline.cssomTree.start + 0.1}
            initial="hidden"
            animate={isVisible ? "visible" : "hidden"}
          >
            <NodeTitle>header</NodeTitle>
            <NodeContent>background, padding</NodeContent>
          </NodeCard>

          {/* h1節點 */}
          <NodeCard
            variants={fadeInVariants}
            custom={timeline.cssomTree.start + 0.3}
            initial="hidden"
            animate={isVisible ? "visible" : "hidden"}
          >
            <NodeTitle>h1</NodeTitle>
            <NodeContent>color, font-size</NodeContent>
          </NodeCard>

          {/* main節點 */}
          <NodeCard
            variants={fadeInVariants}
            custom={timeline.cssomTree.start + 0.6}
            initial="hidden"
            animate={isVisible ? "visible" : "hidden"}
          >
            <NodeTitle>main</NodeTitle>
            <NodeContent>margin</NodeContent>
          </NodeCard>

          {/* p節點 - 移至main後面 */}
          <NodeCard
            variants={fadeInVariants}
            custom={timeline.cssomTree.start + 0.9}
            initial="hidden"
            animate={isVisible ? "visible" : "hidden"}
          >
            <NodeTitle>p</NodeTitle>
            <NodeContent>line-height</NodeContent>
          </NodeCard>

          {/* 樣式優先級與應用結果框 */}
          <StylePriorityBox
            variants={fadeInVariants}
            custom={timeline.cascadePriority.start}
            initial="hidden"
            animate={isVisible ? "visible" : "hidden"}
          >
            {/* 權重衝突示例 */}
            <ConflictExample>
              <ConflictRule>
                <CodeText>
                  p {"{"} color: blue; {"}"}
                </CodeText>
                <div>
                  <span>權重 0,0,0,1</span>
                </div>
              </ConflictRule>
              <hr />
              <ConflictRule>
                <CodeText>
                  main p {"{"} color: red; {"}"}
                </CodeText>
                <div>
                  <span>權重 0,0,0,2</span>
                </div>
              </ConflictRule>

              <WeightExplanation>
                <div>權重格式：(內聯樣式,ID,類/屬性,元素)</div>
                <ExplanationItem>
                  • 權重比較時，從左到右逐位比較，較大的優先
                </ExplanationItem>
                <ExplanationItem>
                  • 權重越高的選擇器，其樣式優先套用
                </ExplanationItem>
                <ExplanationItem>
                  • 當出現樣式衝突時，瀏覽器選擇權重高的規則
                </ExplanationItem>
              </WeightExplanation>
              <StyleResult>
                <div style={{ fontWeight: 600, marginBottom: "0.5rem" }}>
                  Q: 不同的樣式，如果都套用到p身上，結果會是什麼呢：
                </div>
                <div>
                  Answer : 文字會顯示為{" "}
                  <span style={{ color: "red", fontWeight: 500 }}>紅色</span>
                </div>
                <div></div>
              </StyleResult>
            </ConflictExample>
          </StylePriorityBox>

          {/* CSSOM Tree代碼面板 */}
          <CodeBlock style={{ marginTop: "15%", height: "auto", minHeight: "15rem" }}>
          <StatusIndicator
            variants={fadeInVariants}
            custom={timeline.styleResult.start}
            initial="hidden"
            animate={isVisible ? "visible" : "hidden"}
            style={{ top: "-8%", right: "-31%" }}
          >
            <IndicatorStatus>
              <StatusDot />
              <StatusText>4. 建立CSSOM（CSS Object Model）
              </StatusText>
            </IndicatorStatus>
          </StatusIndicator>
            <CodeLabel>CSSOM Tree</CodeLabel>
            <CodeContent>
{`Stylesheet
├── header
│   ├── background: #f0f9ff
│   └── padding: 2rem
├── h1
│   ├── color: #1e40af
│   └── font-size: 2rem
├── main
│   └── margin: 2rem
└── p
    └── line-height: 1.6`}
            </CodeContent>
          </CodeBlock>
        </VisualizationPanel>
      </FlexContainer>
    </Container>
  );
};

export default StyleProcessingAnimation;
