// Interface for connection details
interface ConnectionData {
  from: string;
  to: string[];
  path?: string;
}

const RenderTreeAnimation: React.FC<RenderTreeAnimationProps> = ({ isVisible }) => {
  const timeline = {
    treesDisplay: { start: 0.3 },
    treesContainer: { start: 0.5 },
    connectionLines: { start: 0.6 },
    processArrow: { start: 1.2, duration: 0.5 },
    renderTreeResult: { start: 1.8 },
    hiddenElements: { start: 2.2 }
  };

  // DOM tree structure with levels for grid
  const domTree: TreeNode[][] = [
    [{ id: 'html', label: 'html' }],
    [{ id: 'body', label: 'body' }],
    [{ id: 'header', label: 'header' }, { id: 'main', label: 'main' }],
    [{ id: 'h1', label: 'h1' }, { id: 'p', label: 'p' }],
    [{ id: 'script', label: 'script', hidden: true }],
  ];

  // CORRECTED CSSOM tree structure with levels for grid
  const cssomTree: TreeNode[][] = [
    [{ id: 'styles', label: 'styles' }],
    [{ id: 'header-style', label: 'header' }, { id: 'main-style', label: 'main' }, { id: 'h1-style', label: 'h1' }, { id: 'p-style', label: 'p' }],
  ];

  // Updated Render tree structure with levels for grid - now including h1 and p nodes
  const renderTree: TreeNode[][] = [
    [{ id: 'render-html', label: 'html' }],
    [{ id: 'render-body', label: 'body' }],
    [{ id: 'render-header', label: 'header + style' }, { id: 'render-main', label: 'main + style' }],
    [{ id: 'render-h1', label: 'h1 + style' }, { id: 'render-p', label: 'p + style' }],
  ];

  // DOM tree connections definition
  const domConnections: ConnectionData[] = [
    { from: 'html', to: ['body'] },
    { from: 'body', to: ['header', 'main'] },
    { from: 'header', to: ['h1'] },
    { from: 'main', to: ['p'] },
  ];

  // CORRECTED CSSOM tree connections definition
  const cssomConnections: ConnectionData[] = [
    { from: 'styles', to: ['header-style', 'main-style', 'h1-style', 'p-style'] },
  ];

  // Updated Render tree connections definition - now including connections to h1 and p nodes
  const renderTreeConnections: ConnectionData[] = [
    { from: 'render-html', to: ['render-body'] },
    { from: 'render-body', to: ['render-header', 'render-main'] },
    { from: 'render-header', to: ['render-h1'] },
    { from: 'render-main', to: ['render-p'] },
  ];

  // Refs for DOM node elements
  const nodeRefs = useRef<{ [key: string]: HTMLDivElement | null }>({});
  
  // DOM tree connection container ref
  const domConnectionsContainerRef = useRef<HTMLDivElement>(null);
  
  // CSSOM tree connection container ref
  const cssomConnectionsContainerRef = useRef<HTMLDivElement>(null);
  
  // Render tree connection container ref
  const renderTreeConnectionsContainerRef = useRef<HTMLDivElement>(null);

  // State for the DOM tree connection paths
  const [domConnectionPaths, setDomConnectionPaths] = useState<{ [key: string]: string }>({});
  
  // State for the CSSOM tree connection paths
  const [cssomConnectionPaths, setCssomConnectionPaths] = useState<{ [key: string]: string }>({});
  
  // State for the render tree connection paths
  const [renderTreeConnectionPaths, setRenderTreeConnectionPaths] = useState<{ [key: string]: string }>({});

  // Calculate the connection paths when visible or on window resize
  useEffect(() => {
    if (!isVisible) return;

    const calculateConnections = (
      connections: ConnectionData[], 
      containerElement: HTMLDivElement | null,
      setConnectionPaths: React.Dispatch<React.SetStateAction<{ [key: string]: string }>>
    ) => {
      const paths: { [key: string]: string } = {};

      // Skip calculation if container element isn't available
      if (!containerElement) return;

      const containerRect = containerElement.getBoundingClientRect();

      connections.forEach(connection => {
        const fromElement = nodeRefs.current[connection.from];
        
        if (!fromElement) return;
        
        const fromRect = fromElement.getBoundingClientRect();
        const fromX = fromRect.left + fromRect.width / 2 - containerRect.left;
        const fromY = fromRect.top + fromRect.height - containerRect.top;

        connection.to.forEach(toId => {
          const toElement = nodeRefs.current[toId];
          
          if (!toElement) return;
          
          const toRect = toElement.getBoundingClientRect();
          const toX = toRect.left + toRect.width / 2 - containerRect.left;
          const toY = toRect.top - containerRect.top;

          // Create bezier curve path
          const controlY = (fromY + toY) / 2;
          const path = `M${fromX},${fromY} C${fromX},${controlY} ${toX},${controlY} ${toX},${toY}`;
          
          paths[`${connection.from}_${toId}`] = path;
        });
      });

      setConnectionPaths(paths);
    };

    // Calculate all tree connections
    const calculateAllConnections = () => {
      calculateConnections(domConnections, domConnectionsContainerRef.current, setDomConnectionPaths);
      calculateConnections(cssomConnections, cssomConnectionsContainerRef.current, setCssomConnectionPaths);
      calculateConnections(renderTreeConnections, renderTreeConnectionsContainerRef.current, setRenderTreeConnectionPaths);
    };

    // Initial calculation after a short delay to ensure nodes are rendered
    const timer = setTimeout(calculateAllConnections, 100);
    
    // Recalculate on window resize
    window.addEventListener('resize', calculateAllConnections);
    
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', calculateAllConnections);
    };
  }, [isVisible, domConnections, cssomConnections, renderTreeConnections]);

  return (
    <Container>
      {/* Container that wraps both DOM and CSSOM trees */}
      <TreesContainer
        initial={{ opacity: 0, scale: 0.95 }}
        animate={isVisible ? { opacity: 1, scale: 1 } : { opacity: 0, scale: 0.95 }}
        transition={{ delay: timeline.treesContainer.start, duration: 0.4 }}
      >
        <TreesContainerHeader>
          <TreesContainerTitle>Browser's Internal Representation</TreesContainerTitle>
        </TreesContainerHeader>

        {/* Arrow pointing to Render Tree */}
        <ArrowContainer
          initial={{ opacity: 0 }}
          animate={isVisible ? { opacity: 1 } : { opacity: 0 }}
          transition={{ delay: timeline.processArrow.start, duration: 0.3 }}
        >
          <Arrow
            initial={{ height: 0 }}
            animate={isVisible ? { height: 60 } : { height: 0 }}
            transition={{ 
              delay: timeline.processArrow.start, 
              duration: timeline.processArrow.duration 
            }}
          />
          <ProcessLabel
            initial={{ opacity: 0 }}
            animate={isVisible ? { opacity: 1 } : { opacity: 0 }}
            transition={{ 
              delay: timeline.processArrow.start + 0.2, 
              duration: 0.3 
            }}
          >
            Construction Process
          </ProcessLabel>
        </ArrowContainer>

        {/* DOM Tree */}
        <DOMTreeSection ref={domConnectionsContainerRef}>
          <DOMTitle>DOM Tree</DOMTitle>

          {/* SVG for connection lines - positioned absolutely within the container */}
          {isVisible && (
            <ConnectionsContainer>
              {/* Render all DOM connection paths */}
              {Object.entries(domConnectionPaths).map(([key, path]) => (
                <ConnectionPath
                  key={key}
                  d={path}
                  initial={{ pathLength: 0, opacity: 0 }}
                  animate={{ 
                    pathLength: 1, 
                    opacity: 1
                  }}
                  transition={{ 
                    pathLength: { 
                      delay: timeline.connectionLines.start + (parseInt(key.split('_')[0].replace(/\D/g, '')) * 0.1),
                      duration: 0.4 
                    },
                    opacity: { 
                      delay: timeline.connectionLines.start + (parseInt(key.split('_')[0].replace(/\D/g, '')) * 0.1), 
                      duration: 0.1 
                    }
                  }}
                />
              ))}
            </ConnectionsContainer>
          )}

          {domTree.map((level, levelIndex) => (
            <TreeLevel 
              key={`dom-level-${levelIndex}`}
              style={{
                gridTemplateColumns: `repeat(${level.length}, 1fr)`
              }}
            >
              {level.map((node) => (
                <NodeWrapper
                  key={node.id}
                  ref={(el) => { nodeRefs.current[node.id] = el; }}
                  initial={{ opacity: 0, scale: 0.8 }}
                  animate={isVisible ? 
                    node.hidden ? { opacity: 0.3, scale: 0.8 } : { opacity: 1, scale: 1 } 
                    : { opacity: 0, scale: 0.8 }
                  }
                  transition={{ delay: timeline.treesDisplay.start, duration: 0.3 }}
                >
                  <DOMNode hidden={node.hidden}>{node.label}</DOMNode>
                </NodeWrapper>
              ))}
            </TreeLevel>
          ))}
        </DOMTreeSection>

        {/* CSSOM Tree - CORRECTED STRUCTURE */}
        <CSSOMTreeSection ref={cssomConnectionsContainerRef}>
          <CSSOMTitle>CSSOM Tree</CSSOMTitle>
          {/* SVG for connection lines - positioned absolutely within the container */}
          {isVisible && (
            <ConnectionsContainer>
              {/* Render all CSSOM connection paths */}
              {Object.entries(cssomConnectionPaths).map(([key, path]) => (
                <ConnectionPath
                  key={key}
                  d={path}
                  initial={{ pathLength: 0, opacity: 0 }}
                  animate={{ 
                    pathLength: 1, 
                    opacity: 1
                  }}
                  transition={{ 
                    pathLength: { 
                      delay: timeline.connectionLines.start + (parseInt(key.split('_')[0].replace(/\D/g, '')) * 0.1),
                      duration: 0.4 
                    },
                    opacity: { 
                      delay: timeline.connectionLines.start + (parseInt(key.split('_')[0].replace(/\D/g, '')) * 0.1), 
                      duration: 0.1 
                    }
                  }}
                />
              ))}
            </ConnectionsContainer>
          )}

          {cssomTree.map((level, levelIndex) => (
            <TreeLevel
              key={`cssom-level-${levelIndex}`}
              style={{
                gridTemplateColumns: `repeat(${level.length}, 1fr)`
              }}
            >
              {level.map((node) => (
                <NodeWrapper
                  key={node.id}
                  ref={(el) => { nodeRefs.current[node.id] = el; }}
                  initial={{ opacity: 0, scale: 0.8 }}
                  animate={isVisible ? { opacity: 1, scale: 1 } : { opacity: 0, scale: 0.8 }}
                  transition={{ delay: timeline.treesDisplay.start, duration: 0.3 }}
                >
                  <CSSOMNode>{node.label}</CSSOMNode>
                </NodeWrapper>
              ))}
            </TreeLevel>
          ))}
        </CSSOMTreeSection>
      </TreesContainer>

      {/* Render Tree Section */}
      <RenderTreeSection ref={renderTreeConnectionsContainerRef}>
        {/* SVG for connection lines - positioned absolutely within the container */}
        {isVisible && (
          <ConnectionsContainer>
            {/* Render all render tree connection paths */}
            {Object.entries(renderTreeConnectionPaths).map(([key, path]) => (
              <ConnectionPath
                key={key}
                d={path}
                initial={{ pathLength: 0, opacity: 0 }}
                animate={{ 
                  pathLength: 1, 
                  opacity: 1
                }}
                transition={{ 
                  pathLength: { 
                    delay: timeline.renderTreeResult.start + (key.includes('render-header') || key.includes('render-main') ? 0.2 : 0),
                    duration: 0.4 
                  },
                  opacity: { 
                    delay: timeline.renderTreeResult.start + (key.includes('render-header') || key.includes('render-main') ? 0.2 : 0), 
                    duration: 0.1 
                  }
                }}
              />
            ))}
          </ConnectionsContainer>
        )}

        <RenderTreeTitle
          initial={{ opacity: 0 }}
          animate={isVisible ? { opacity: 1 } : { opacity: 0 }}
          transition={{ delay: timeline.renderTreeResult.start - 0.2 }}
        >
          Render Tree
        </RenderTreeTitle>
        {renderTree.map((level, levelIndex) => (
          <TreeLevel
            key={`render-level-${levelIndex}`}
            style={{
              gridTemplateColumns: `repeat(${level.length}, 1fr)`
            }}
          >
            {level.map((node, nodeIndex) => (
              <NodeWrapper
                key={node.id}
                ref={(el) => { nodeRefs.current[node.id] = el; }}
                initial={{ opacity: 0, scale: 0.8 }}
                animate={isVisible ? { opacity: 1, scale: 1 } : { opacity: 0, scale: 0.8 }}
                transition={{ 
                  delay: timeline.renderTreeResult.start + (levelIndex * 0.2) + (nodeIndex * 0.1), 
                  duration: 0.3 
                }}
              >
                <RenderTreeNode>{node.label}</RenderTreeNode>
              </NodeWrapper>
            ))}
          </TreeLevel>
        ))}
      </RenderTreeSection>

   
    </Container>
  );
};

export default RenderTreeAnimation;